import React, { useState, useEffect, useCallback } from 'react';
import { PageBanner, NavPills, ScoreCard, SvgGauge, SectionHeader, DataTable, Spinner, Footer } from '../components/UIComponents';
import { getMaturityQuestions, submitMaturity, downloadMaturityExcel, downloadMaturityPDF } from '../utils/api';

/* ═══════════════════════════════════════════════════════════════
   EMBEDDED QUESTION BANK — mirrors backend DataMaturity/config.py
   The grid renders IMMEDIATELY from this data.
   If the backend API is running, it will override with fresh data.
   ═══════════════════════════════════════════════════════════════ */
const FALLBACK_QUESTION_BANK = {
  "Data Governance": [
    { id: "DG-1", section: "Data Management Strategy (DMS)", question: "Documented Data Management Strategy exists (vision, scope, objectives).", weight: 2 },
    { id: "DG-2", section: "Data Management Strategy (DMS)", question: "Stakeholders are involved in strategy creation and review.", weight: 1 },
    { id: "DG-3", section: "Data Management Strategy (DMS)", question: "Strategy is approved, published, and communicated to relevant stakeholders.", weight: 1 },
    { id: "DG-4", section: "Roles & Responsibilities", question: "Data roles (Owner, Steward, Custodian) are defined for the object.", weight: 2 },
    { id: "DG-5", section: "Roles & Responsibilities", question: "Roles and responsibilities are documented and communicated.", weight: 1 },
    { id: "DG-6", section: "Policies & Standards", question: "Governance policies/standards exist (naming, definitions, approvals).", weight: 2 },
    { id: "DG-7", section: "Policies & Standards", question: "Policies are periodically reviewed and updated.", weight: 1 },
    { id: "DG-8", section: "DMO", question: "Data Management Office (DMO) / governance forum exists.", weight: 2 },
    { id: "DG-9", section: "DMO", question: "Operating model & governance cadence are defined (RACI, forums, KPIs).", weight: 1 },
    { id: "DG-10", section: "Change Management", question: "Change control process exists for master data requests/updates.", weight: 2 },
    { id: "DG-11", section: "Change Management", question: "Training / enablement exists for users and data stewards.", weight: 1 },
    { id: "DG-12", section: "Issue Management", question: "Issue logging, triage, and resolution workflow exists.", weight: 1 },
    { id: "DG-13", section: "Issue Management", question: "Root-cause analysis and lessons learned are captured.", weight: 1 },
    { id: "DG-14", section: "Metadata", question: "Metadata (definitions, owners, rules) is managed in a repository/catalog.", weight: 1 },
  ],
  "Data Quality": [
    { id: "DQ-1", section: "Assessment & Rules", question: "Data quality assessment policy exists (what, how often, ownership).", weight: 2 },
    { id: "DQ-2", section: "Assessment & Rules", question: "DQ rules are defined (completeness, validity, uniqueness, consistency).", weight: 2 },
    { id: "DQ-3", section: "Assessment & Rules", question: "DQ rules cover critical fields and are documented with thresholds.", weight: 2 },
    { id: "DQ-4", section: "Monitoring", question: "DQ monitoring is periodic and tracked (dashboards/scorecards).", weight: 2 },
    { id: "DQ-5", section: "Monitoring", question: "Automated validation exists (API checks, format checks, reference checks).", weight: 1 },
    { id: "DQ-6", section: "Duplicates", question: "Duplicate detection & golden record process exists.", weight: 2 },
    { id: "DQ-7", section: "Profiling", question: "Data profiling is performed using tools/standard techniques.", weight: 1 },
    { id: "DQ-8", section: "Profiling", question: "Anomalies/inconsistencies are identified and resolved consistently.", weight: 1 },
    { id: "DQ-9", section: "Standardization", question: "Standardization rules exist (formats, naming conventions, codes).", weight: 2 },
    { id: "DQ-10", section: "Standardization", question: "Uniform definitions and formatting are applied across datasets/systems.", weight: 1 },
    { id: "DQ-11", section: "Cleansing", question: "Cleansing workflow/tools exist (issue queues, approvals, audit trail).", weight: 2 },
    { id: "DQ-12", section: "Cleansing", question: "Recurring cleansing is planned (not only ad-hoc one-time fixes).", weight: 1 },
  ],
  "Data Integration & Interoperability": [
    { id: "DI-1", section: "Integration Strategy & Architecture", question: "Enterprise-wide integration strategy exists (APIs/ETL/events), aligned to target state.", weight: 2 },
    { id: "DI-2", section: "Integration Strategy & Architecture", question: "System of Record (SoR) / System of Entry is clearly defined per object.", weight: 2 },
    { id: "DI-3", section: "Integration Strategy & Architecture", question: "Integration flows and interfaces are documented (source-to-target mapping).", weight: 2 },
    { id: "DI-4", section: "Integration Technology & Tools", question: "Integration platform/tooling supports scalability & performance requirements.", weight: 1 },
    { id: "DI-5", section: "Integration Technology & Tools", question: "Logging, monitoring, reconciliation, and audit trails exist for data movement.", weight: 2 },
  ],
};

const DEFAULT_OBJECTS = ['Customer', 'Vendor Master', 'Item Master', 'Price', 'Finance'];

const RATING_OPTIONS = [
  { label: '1 - Adhoc', value: '1' },
  { label: '2 - Repeatable', value: '2' },
  { label: '3 - Defined', value: '3' },
  { label: '4 - Managed', value: '4' },
  { label: '5 - Optimised', value: '5' },
];

function buildInitialResponses(questionBank, objectsList) {
  const resp = {};
  Object.entries(questionBank).forEach(([dim, qList]) => {
    resp[dim] = qList.map((q) => {
      const row = { 'Question': q.question, 'Question ID': q.id, 'Section': q.section, 'Weight': q.weight || 1 };
      objectsList.forEach((obj) => { row[obj] = ''; });
      return row;
    });
  });
  return resp;
}

function groupBySection(qList) {
  const groups = [];
  let curSec = null, curGrp = null;
  (qList || []).forEach((q, idx) => {
    if (q.section !== curSec) {
      curSec = q.section;
      curGrp = { section: q.section, questions: [] };
      groups.push(curGrp);
    }
    curGrp.questions.push({ ...q, originalIndex: idx });
  });
  return groups;
}

export default function MaturityPage({ onNavigate, sessionId, dqScore }) {
  const [clientName, setClientName] = useState('');
  const [objects, setObjects] = useState([...DEFAULT_OBJECTS]);
  const [mastersApplicable, setMastersApplicable] = useState(true);
  const [benchmark, setBenchmark] = useState(3.0);
  const [target, setTarget] = useState(3.0);
  const [lowThr, setLowThr] = useState(2.0);

  const [questions, setQuestions] = useState(FALLBACK_QUESTION_BANK);
  const [dims, setDims] = useState(Object.keys(FALLBACK_QUESTION_BANK));
  const [responses, setResponses] = useState(() => buildInitialResponses(FALLBACK_QUESTION_BANK, DEFAULT_OBJECTS));
  const [activeDim, setActiveDim] = useState(Object.keys(FALLBACK_QUESTION_BANK)[0]);

  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [results, setResults] = useState(null);
  const [error, setError] = useState('');
  const [apiStatus, setApiStatus] = useState('loading');

  const currentObjects = mastersApplicable ? objects : [clientName || 'Overall'];

  // Try loading from API (non-blocking — grid already visible from fallback)
  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const resp = await getMaturityQuestions([], []);
        if (cancelled) return;
        const qData = resp.data.questions || {};
        if (Object.keys(qData).length > 0) {
          setQuestions(qData);
          const dl = Object.keys(qData);
          setDims(dl);
          setActiveDim(dl[0]);
          setResponses(buildInitialResponses(qData, objects));
          setApiStatus('connected');
        } else {
          setApiStatus('offline');
        }
      } catch (e) {
        if (!cancelled) {
          console.warn('API unavailable, using embedded questions:', e.message);
          setApiStatus('offline');
        }
      }
    })();
    return () => { cancelled = true; };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Sync object columns
  useEffect(() => {
    setResponses((prev) => {
      const u = { ...prev };
      Object.keys(u).forEach((dim) => {
        u[dim] = (u[dim] || []).map((row) => {
          const nr = { ...row };
          currentObjects.forEach((o) => { if (!(o in nr)) nr[o] = ''; });
          return nr;
        });
      });
      return u;
    });
  }, [objects, mastersApplicable, clientName]); // eslint-disable-line react-hooks/exhaustive-deps

  const updateResponse = useCallback((dim, qIdx, obj, value) => {
    setResponses((prev) => {
      const u = { ...prev };
      const rows = [...(u[dim] || [])];
      rows[qIdx] = { ...rows[qIdx], [obj]: value };
      u[dim] = rows;
      return u;
    });
  }, []);

  const countFilled = useCallback((dim) => {
    const rows = responses[dim] || [];
    let filled = 0, total = 0;
    rows.forEach((row) => { currentObjects.forEach((obj) => { total++; if (row[obj] && row[obj] !== '') filled++; }); });
    return { filled, total };
  }, [responses, currentObjects]);

  const handleSubmit = async () => {
    if (!clientName.trim()) { setError('Please enter a Client Name.'); return; }
    let hasAny = false;
    for (const dim of dims) { for (const row of (responses[dim] || [])) { for (const obj of currentObjects) { if (row[obj] && row[obj] !== '') { hasAny = true; break; } } if (hasAny) break; } if (hasAny) break; }
    if (!hasAny) { setError('Fill in at least some ratings before submitting.'); return; }
    setLoading(true); setError('');
    try {
      const resp = await submitMaturity({ session_id: sessionId, client_name: clientName, dims, objects: currentObjects, responses, benchmark, target, low_thr: lowThr, dq_score: dqScore });
      setResults(resp.data); setSubmitted(true);
    } catch (e) { setError(e.response?.data?.error || e.message); } finally { setLoading(false); }
  };

  const tp = dims.reduce((a, d) => { const c = countFilled(d); return { filled: a.filled + c.filled, total: a.total + c.total }; }, { filled: 0, total: 0 });

  return (
    <div className="page-maturity">
      <PageBanner icon="📈" badge="Maturity Report" title="Data Maturity Assessment"
        subtitle="Evaluate DAMA maturity dimensions across governance, quality, architecture, integration & privacy with benchmark comparisons." />
      <NavPills current="maturity" onChange={onNavigate} />

      {loading && <Spinner message="Computing scores and building reports..." />}
      {error && <div className="error-banner" style={{ cursor: 'pointer' }} onClick={() => setError('')}>⚠️ {error} <span style={{ float: 'right', fontWeight: 700 }}>✕</span></div>}

      {/* ═══ RESULTS ═══ */}
      {submitted && results && !loading && (
        <div className="maturity-results">
          {dqScore != null && <div className="dq-score-banner"><strong>DQ Engine Score:</strong> {dqScore.toFixed(1)}% → <strong>Level:</strong> {results.dq_maturity_level}</div>}
          <h3 className="subsection-title">📊 Summary Slide</h3>
          {results.slide_png_b64 && <div className="slide-wrap"><img src={`data:image/png;base64,${results.slide_png_b64}`} alt="Maturity Summary" style={{ width: '100%', borderRadius: 14 }} /></div>}
          <h3 className="subsection-title">📐 Dimension-wise Maturity</h3>
          {results.dim_table && <DataTable data={Object.entries(results.dim_table).map(([dim, vals]) => ({ Dimension: dim, ...Object.fromEntries(Object.entries(vals).map(([k, v]) => [k, typeof v === 'number' ? v.toFixed(2) : v])) }))} maxHeight={400} />}
          <div className="gauges-row">{Object.entries(results.domain_scores || {}).map(([dim, s]) => <SvgGauge key={dim} score={Math.min(s * 20, 100)} label={dim} />)}</div>
          {results.overall && <><h3 className="subsection-title">📊 Overall per Object</h3><div className="scores-row">{Object.entries(results.overall).map(([obj, s]) => <ScoreCard key={obj} value={Math.min(s * 20, 100)} label={obj} />)}</div></>}
          <SectionHeader>Download Reports</SectionHeader>
          <div className="download-row">
            <div className="download-card"><div className="dl-icon">📊</div><div className="dl-title">Excel Report</div><a href={downloadMaturityExcel(sessionId)} className="btn-primary" download>⬇ Download Excel</a></div>
            <div className="download-card"><div className="dl-icon">📄</div><div className="dl-title">PDF Report</div><a href={downloadMaturityPDF(sessionId)} className="btn-primary" download>⬇ Download PDF</a></div>
          </div>
          <div style={{ textAlign: 'center', marginTop: '1.5rem' }}><button className="btn-secondary" onClick={() => { setSubmitted(false); setResults(null); }}>✏️ Edit Responses</button></div>
        </div>
      )}

      {/* ═══ FORM ═══ */}
      {!submitted && !loading && (
        <div className="maturity-form">
          {/* Sidebar */}
          <div className="mat-sidebar">
            <div className="sidebar-section">
              <h4>⚙️ Configuration</h4>
              <label className="form-label">Client Name <span className="required">*</span>
                <input type="text" value={clientName} onChange={(e) => setClientName(e.target.value)} placeholder="Organisation name (required)" />
              </label>
              {!clientName.trim() && <p className="field-error">⚠ Required</p>}
            </div>
            <div className="sidebar-section">
              <div style={{ background: 'linear-gradient(135deg, #f5f0fc, #fdf2f8)', border: '2px solid #b09dd6', borderRadius: 12, padding: '0.7rem 0.9rem', boxShadow: '0 2px 10px rgba(91,45,144,0.12)' }}>
                <label className="checkbox-label" style={{ marginBottom: 0 }}>
                  <input type="checkbox" checked={mastersApplicable} onChange={(e) => setMastersApplicable(e.target.checked)} />
                  📋 Include Master Data Objects
                </label>
                <p style={{ fontSize: '0.76rem', color: '#5b2d90', margin: '0.3rem 0 0', lineHeight: 1.4 }}>Enable to evaluate maturity per Master Data Object</p>
              </div>
            </div>
            {mastersApplicable && (
              <div className="sidebar-section">
                <label className="form-label">Master Data Objects
                  <select multiple value={objects} onChange={(e) => setObjects(Array.from(e.target.selectedOptions, (o) => o.value))} style={{ height: 140 }}>
                    {DEFAULT_OBJECTS.map((o) => <option key={o}>{o}</option>)}
                  </select>
                </label>
              </div>
            )}
            <div className="sidebar-section">
              <label className="form-label">Industry Benchmark<input type="number" min="1" max="5" step="0.1" value={benchmark} onChange={(e) => setBenchmark(parseFloat(e.target.value) || 3.0)} /></label>
              <label className="form-label">Target Score<input type="number" min="1" max="5" step="0.1" value={target} onChange={(e) => setTarget(parseFloat(e.target.value) || 3.0)} /></label>
              <label className="form-label">Exception Threshold (≤)<input type="range" min="1" max="5" step="0.5" value={lowThr} onChange={(e) => setLowThr(parseFloat(e.target.value))} /><span className="range-val">{lowThr}</span></label>
            </div>
            <div style={{ fontSize: '0.72rem', color: apiStatus === 'connected' ? '#059669' : '#d97706', padding: '0.4rem 0.6rem', background: apiStatus === 'connected' ? '#f0fdf4' : '#fffbeb', borderRadius: 8, textAlign: 'center', marginTop: '0.5rem', border: `1px solid ${apiStatus === 'connected' ? '#bbf7d0' : '#fde68a'}` }}>
              {apiStatus === 'connected' ? '🟢 Backend connected' : apiStatus === 'offline' ? '🟡 Using embedded questions' : '⏳ Connecting...'}
            </div>
          </div>

          {/* Main: Tabs + Grid */}
          <div className="mat-main">
            <div className="tab-bar">
              {dims.map((d) => {
                const { filled, total } = countFilled(d);
                return (
                  <button key={d} className={`tab-btn ${activeDim === d ? 'active' : ''}`} onClick={() => setActiveDim(d)}>
                    {d}
                    {total > 0 && <span style={{ marginLeft: 6, fontSize: '0.68rem', fontWeight: 700, background: filled === total && total > 0 ? '#059669' : filled > 0 ? '#5b2d90' : '#d9cef0', color: filled > 0 ? '#fff' : '#5b2d90', borderRadius: 999, padding: '1px 6px' }}>{filled}/{total}</span>}
                  </button>
                );
              })}
            </div>

            {/* ═══ QUESTION GRID ═══ */}
            {activeDim && questions[activeDim] && questions[activeDim].length > 0 && (
              <div className="question-grid">
                <div className="q-header-row">
                  <div className="q-header-q" style={{ flex: '0 0 55px', textAlign: 'center' }}>ID</div>
                  <div className="q-header-q" style={{ flex: 3 }}>Question</div>
                  {currentObjects.map((obj) => <div key={obj} className="q-header-obj">{obj}</div>)}
                </div>

                {groupBySection(questions[activeDim]).map((group) => (
                  <React.Fragment key={group.section}>
                    <div style={{ background: '#f5f0fc', borderLeft: '4px solid #5b2d90', padding: '0.5rem 1rem', fontWeight: 700, fontSize: '0.84rem', color: '#5b2d90', borderBottom: '1px solid #d9cef0' }}>
                      📂 {group.section}
                    </div>
                    {group.questions.map((q) => {
                      const qIdx = q.originalIndex;
                      const rowData = responses[activeDim]?.[qIdx];
                      return (
                        <div key={q.id} className="q-row">
                          <div className="q-text" style={{ flex: '0 0 55px', textAlign: 'center', fontWeight: 700, color: '#7a7a9a', fontSize: '0.74rem' }}>{q.id}</div>
                          <div className="q-text" style={{ flex: 3 }}>
                            {q.question}
                            {q.weight > 1 && <span style={{ marginLeft: 6, fontSize: '0.63rem', background: '#ede8f7', color: '#5b2d90', borderRadius: 999, padding: '1px 5px', fontWeight: 700 }}>w:{q.weight}</span>}
                          </div>
                          {currentObjects.map((obj) => {
                            const val = rowData?.[obj] || '';
                            return (
                              <div key={obj} className="q-input">
                                <select value={val} onChange={(e) => updateResponse(activeDim, qIdx, obj, e.target.value)}
                                  style={{ background: val ? '#f0fdf4' : '#fff', borderColor: val ? '#bbf7d0' : '#d9cef0', fontSize: '0.78rem' }}>
                                  <option value="">—</option>
                                  {RATING_OPTIONS.map((r) => <option key={r.value} value={r.value}>{r.label}</option>)}
                                </select>
                              </div>
                            );
                          })}
                        </div>
                      );
                    })}
                  </React.Fragment>
                ))}
              </div>
            )}

            {/* Progress */}
            <div style={{ background: 'linear-gradient(135deg, #f5f0fc, #fdf2f8)', border: '1.5px solid #d9cef0', borderRadius: 10, padding: '0.6rem 1rem', margin: '0.8rem 0', fontSize: '0.82rem', color: '#3b1f72' }}>
              <strong>Overall progress:</strong> {tp.filled} / {tp.total} cells filled ({tp.total > 0 ? Math.round(tp.filled / tp.total * 100) : 0}%)
              <div style={{ marginTop: 4, height: 6, background: '#e8e2f5', borderRadius: 999, overflow: 'hidden' }}>
                <div style={{ width: `${tp.total > 0 ? (tp.filled / tp.total * 100) : 0}%`, height: '100%', borderRadius: 999, background: 'linear-gradient(90deg, #5b2d90, #b10f74)', transition: 'width 0.3s' }} />
              </div>
            </div>

            <div className="submit-section">
              <button className="btn-run" onClick={handleSubmit} disabled={!clientName.trim() || loading || tp.filled === 0}>
                ✅ Submit & Generate Report
              </button>
              {tp.filled === 0 && <p style={{ fontSize: '0.8rem', color: '#d97706', marginTop: '0.5rem' }}>Fill in at least some ratings above to enable submission.</p>}
            </div>
          </div>
        </div>
      )}

      <Footer />
    </div>
  );
}
